// io.mino.mobi — shared front-end logic: auth wiring + compose form + ticket
// submission to the author's own PDS via the shared OAuth worker.
// Imported from ./vendor/auth.js — a deploy-time copy of the canonical shared
// client at packages/oauth-client/auth.js (single source of truth; the copy is
// gitignored and regenerated by deploy-io.yml + scripts/vendor-io.sh, so it
// never drifts). See io/DESIGN.md §3.2.
import { AuthClient } from './vendor/auth.js';

export const auth = new AuthClient();

let CONFIG = {
  collection: 'com.minomobi.io.ticket',
  boardAnchor: 'https://io.mino.mobi/anchor/tickets/v1',
  scope: 'atproto repo:com.minomobi.io.ticket',
  kinds: ['bug', 'feature', 'idea'],
  severities: ['low', 'med', 'high'],
};

export async function loadConfig() {
  try {
    const res = await fetch('/api/config');
    if (res.ok) CONFIG = { ...CONFIG, ...(await res.json()) };
  } catch { /* use defaults */ }
  return CONFIG;
}

export function getConfig() { return CONFIG; }

// ── Auth ──────────────────────────────────────────────────────────────────

export async function initAuth(onChange) {
  if (onChange) auth.onAuthChange(onChange);
  const user = await auth.init();
  if (onChange) onChange(user);
  return user;
}

export async function login(handle) {
  if (!handle) { toast('Enter your Bluesky handle', true); return; }
  try {
    await auth.login(handle, { scope: CONFIG.scope });
  } catch (e) {
    toast(e.message || 'Login failed', true);
  }
}

export async function logout() { await auth.logout(); }

// ── Ticket submission ───────────────────────────────────────────────────────

/**
 * Write a ticket to the logged-in user's own PDS, then poke the indexer so the
 * board reflects it without waiting for cron.
 * @param {{kind, title, body?, site?, url?, repo?, severity?, tags?}} fields
 */
export async function submitTicket(fields) {
  const user = auth.getUser();
  if (!user) throw new Error('Not logged in');
  const record = {
    $type: CONFIG.collection,
    kind: fields.kind,
    title: fields.title,
    board: CONFIG.boardAnchor,
    createdAt: new Date().toISOString(),
    source: { kind: 'manual' },
  };
  if (fields.body) record.body = fields.body;
  if (fields.site) record.site = fields.site;
  if (fields.url) record.url = fields.url;
  if (fields.repo) record.repo = fields.repo;
  if (fields.severity) record.severity = fields.severity;
  if (fields.tags && fields.tags.length) record.tags = fields.tags;

  const result = await auth.pds.createRecord(CONFIG.collection, record);
  // Best-effort: ask the worker to index this record now.
  fetch('/api/index/notify', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ uri: result.uri }),
  }).catch(() => {});
  return result;
}

// ── Toast ───────────────────────────────────────────────────────────────────

let toastTimer = null;
export function toast(msg, isErr) {
  let el = document.querySelector('.toast');
  if (!el) {
    el = document.createElement('div');
    el.className = 'toast';
    document.body.appendChild(el);
  }
  el.textContent = msg;
  el.classList.toggle('err', !!isErr);
  el.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => el.classList.remove('show'), 3500);
}
